import React, {useEffect, useRef, useState} from 'react';

function User(props){
    const {isPreferencesEnable, onPreferencesChange, userData, onLogout} = props;
    const [aberto, setAberto] = useState(isPreferencesEnable);
    const menuRef = useRef(null);
    const [showEdit, setShowEdit] = useState(false);
    const [menuType, setMenuType] = useState("profile");

    useEffect(() => {
        setAberto(isPreferencesEnable);
    },[isPreferencesEnable]);

    useEffect(() => {
        //setAberto(isPreferencesEnable);
        const handleClickOutside = (event) => {
            if (aberto && menuRef.current && !menuRef.current.contains(event.target)) {
                onPreferencesChange(false);
                setAberto(false);
            }

        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    });

    return (
        <div
            ref={menuRef}
            className={`user-card position-absolute top-50 start-0 p-2 ${isPreferencesEnable ? "open" : ""}`}
        >
            <div className="user-card-sidebar">
                <div className="user-settings-container">
                    <ul className="user-settings">
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="general-button"
                                    onClick={() => {
                                        setMenuType("general")
                                    }}
                                >
                                    <i className="bi bi-laptop"></i>
                                    General
                                </button>
                            </div>
                        </li>
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="account-button"
                                    onClick={() => {
                                        setMenuType("account")
                                    }}
                                >
                                    <i className="bi bi-key"></i>
                                    Account
                                </button>
                            </div>
                        </li>
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="appearance-button"
                                    onClick={() => {
                                        setMenuType("appearance")
                                    }}
                                >
                                    <i className="bi bi-brush"></i>
                                    Appearance
                                </button>
                            </div>
                        </li>
                        <li className="user-settings-item">
                            <div>
                                <button
                                    className="help-button"
                                    onClick={() => {
                                        setMenuType("help")
                                    }}
                                >
                                    <i className="bi bi-info-circle"></i>
                                    Help
                                </button>
                            </div>
                        </li>
                    </ul>
                </div>
                <div className="user-settings-item">
                    <div className="user-settings-item-content">
                        <button
                            className="profile-button"
                            onClick={() => {
                                setMenuType("profile")
                            }}
                        >
                            <i className="bi bi-person-circle"></i>
                            Profile
                        </button>
                    </div>
                </div>
            </div>
            <div
                className="user-card-container"
                hidden={menuType != "profile"}
            >
                <div className="user-card-settings">
                    <div className="user-picture-container"
                         onMouseEnter={() => {
                             setShowEdit(true);
                         }}
                         onMouseLeave={() => {
                             setShowEdit(false);
                         }}
                    >
                        {showEdit && (<i className="bi bi-pencil"></i>)}
                        {userData && (
                            <img
                                className="user-picture"
                                src={userData.imagePath}
                                alt="">
                            </img>
                        )}
                    </div>
                    <div className="user-card-name">
                        {userData && (
                            <h4>
                                {userData.name}
                            </h4>
                        )}
                        <i className="bi bi-pencil"></i>
                    </div>
                    <div className="user-card-description">
                        <p>Description</p>
                        <div className="user-card-description-content">
                            {userData && (
                                <p>
                                    {userData.description}
                                </p>
                            )}
                            <i className="bi bi-pencil"></i>
                        </div>
                    </div>
                </div>
                <div className="user-card-session">
                    <button
                        className="logoff-button"
                        onClick={() => {
                            onLogout();
                            setAberto(false);
                            onPreferencesChange(false);
                        }}
                    >
                        Log Off
                    </button>
                </div>
            </div>
            <div
                className="general-card-container"
                hidden={menuType != "general"}
            >
                <h1>GENERAL</h1>
            </div>
            <div
                className="account-card-container"
                hidden={menuType != "account"}
            >
                <h1>ACCOUNT</h1>
            </div>
            <div
                className="appearance-card-container"
                hidden={menuType != "appearance"}
            >
                <h1>APPEARANCE</h1>
            </div>
            <div
                className="help-card-container"
                hidden={menuType != "help"}
            >
                <h1>HELP</h1>
            </div>
        </div>
    );
}

export default User;
